def validate(args, output):
    seq = args[0]
    if not isinstance(output, list) or len(output) != len(seq):
        return False
    for x in output:
        if x not in (0, 1):
            return False
    # split into the two subsequences
    a = [seq[i] for i in range(len(seq)) if output[i] == 0]
    b = [seq[i] for i in range(len(seq)) if output[i] == 1]
    def depth(chars):
        d = 0
        mx = 0
        for ch in chars:
            if ch == '(':
                d += 1
                mx = max(mx, d)
            else:
                d -= 1
                if d < 0:
                    return None
        if d != 0:
            return None
        return mx
    da = depth(a)
    db = depth(b)
    if da is None or db is None:
        return False
    got = max(da, db)
    # optimal achievable maximum depth is ceil(total_depth / 2)
    total = 0
    cur = 0
    for ch in seq:
        if ch == '(':
            cur += 1
            total = max(total, cur)
        else:
            cur -= 1
    optimal = (total + 1) // 2
    return got == optimal

judge.validator_javascript:
function validate(args, output) {
    const seq = args[0];
    if (!Array.isArray(output) || output.length !== seq.length) return false;
    for (const x of output) if (x !== 0 && x !== 1) return false;
    const a = [], b = [];
    for (let i = 0; i < seq.length; i++) {
        if (output[i] === 0) a.push(seq[i]); else b.push(seq[i]);
    }
    function depth(chars) {
        let d = 0, mx = 0;
        for (const ch of chars) {
            if (ch === '(') { d += 1; if (d > mx) mx = d; }
            else { d -= 1; if (d < 0) return null; }
        }
        if (d !== 0) return null;
        return mx;
    }
    const da = depth(a), db = depth(b);
    if (da === null || db === null) return false;
    const got = Math.max(da, db);
    let total = 0, cur = 0;
    for (const ch of seq) {
        if (ch === '(') { cur += 1; if (cur > total) total = cur; }
        else cur -= 1;
    }
    const optimal = Math.floor((total + 1) / 2);
    return got === optimal;
}

