class Solution:
    def maxDepthAfterSplit(self, seq):
        # independent approach: assign by index of open parens in sorted-by-depth order
        ans = [0] * len(seq)
        depth = 0
        for i, ch in enumerate(seq):
            if ch == '(':
                depth += 1
                ans[i] = depth % 2
            else:
                ans[i] = depth % 2
                depth -= 1
        return ans

